#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAXN 100005
#define MAXM 300005
typedef long long ll;
typedef struct {
    int to;
    int w;
    int next;
} Edge;
Edge edges[MAXM];
int head[MAXN];
int edge_cnt = 0;
ll dist[MAXN];
int src[MAXN];
void add_edge(int u, int v, int w) {
    edges[edge_cnt].to = v;
    edges[edge_cnt].w = w;
    edges[edge_cnt].next = head[u];
    head[u] = edge_cnt++;
}
int main() {
    int N, M, K;
    scanf("%d %d %d", &N, &M, &K);
    for (int i = 1; i <= N; i++) {
        head[i] = -1;
        dist[i] = LLONG_MAX;
        src[i] = 0;
    }
    int out[K];
    for (int i = 0; i < K; i++) {
        scanf("%d", &out[i]);
        dist[out[i]] = 0;
        src[out[i]] = out[i];
    }
    for (int i = 0; i < M; i++) {
        int x, y, z;
        scanf("%d %d %d", &x, &y, &z);
        add_edge(x, y, z);
        add_edge(y, x, z);
    }
    ll ans = LLONG_MAX;
    for (int i = 0; i < K; i++) {
        for (int j = i + 1; j < K; j++) {
            ll d = dist[out[i]] + dist[out[j]];
            if (d < ans) ans = d;
        }
    }
    printf("%lld\n", ans);
    return 0;
}

