#include <bits/stdc++.h>
using namespace std;
#define MAXN 100005
#define MAXM 300005
typedef long long ll;
typedef pair<ll, int> pli;
vector<pair<int, int>> graph[MAXN];
ll dist[MAXN];
int src[MAXN];
priority_queue<pli, vector<pli>, greater<pli>> pq;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int N, M, K;
    cin >> N >> M >> K;
    for (int i = 1; i <= N; i++) {
        dist[i] = LLONG_MAX;
        src[i] = 0;
    }
    vector<int> out(K);
    for (int i = 0; i < K; i++) {
        cin >> out[i];
        dist[out[i]] = 0;
        src[out[i]] = out[i];
        pq.push({0, out[i]});
    }
    for (int i = 0; i < M; i++) {
        int x, y, z;
        cin >> x >> y >> z;
        graph[x].push_back({y, z});
        graph[y].push_back({x, z});
    }
    ll ans = LLONG_MAX;
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d != dist[u]) continue;
        for (auto [v, w] : graph[u]) {
            ll nd = d + w;
            if (nd < dist[v]) {
                dist[v] = nd;
                pq.push({nd, v});
            }
        }
    }
    for (int i = 0; i < K; i++) {
        for (int j = i + 1; j < K; j++) {
            ll d = dist[out[i]] + dist[out[j]];
            if (d < ans) ans = d;
        }
    }
    cout << ans << "\n";
    return 0;
}

