import java.io.*;
import java.util.*;
public class Main {
    static final int MAXN = 100005;
    static class Pair {
        int node;
        long wt;
        Pair(int n, long w) {
            node = n;
            wt = w;
        }
    }
    static class State {
        long cost;
        int node;
        int par;
        State(long c, int n, int p) {
            cost = c;
            node = n;
            par = p;
        }
    }
    static ArrayList<Pair>[] graph = new ArrayList[MAXN];
    static long[] vis = new long[MAXN];
    static long n, m, k;
    static long dijk(long[] arr) {
        PriorityQueue<State> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a.cost));
        for (int i = 0; i < k; i++) {
            pq.add(new State(0, (int)arr[i], (int)arr[i]));
        }
        long[] cost = new long[(int)n + 1];
        long ans = Long.MAX_VALUE;
        while (!pq.isEmpty()) {
            State cur = pq.poll();
            long cst = cur.cost;
            int node = cur.node;
            int par = cur.par;
            if (vis[node] != 0) {
                if (vis[node] == par) {
                    // do nothing
                } else {
                    ans = Math.min(ans, cost[node] + cst);
                }
                continue;
            }
            cost[node] = cst;
            vis[node] = par;
            for (Pair edge : graph[node]) {
                pq.add(new State(cst + edge.wt, edge.node, par));
            }
        }
        return ans;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        n = Long.parseLong(st.nextToken());
        m = Long.parseLong(st.nextToken());
        k = Long.parseLong(st.nextToken());
        for (int i = 0; i < MAXN; i++) graph[i] = new ArrayList<>();
        long[] a = new long[(int)k];
        st = new StringTokenizer(br.readLine());
        for (int i = 0; i < k; i++) {
            a[i] = Long.parseLong(st.nextToken());
        }
        for (int i = 0; i < m; i++) {
            st = new StringTokenizer(br.readLine());
            int x = Integer.parseInt(st.nextToken());
            int y = Integer.parseInt(st.nextToken());
            long z = Long.parseLong(st.nextToken());
            graph[x].add(new Pair(y, z));
            graph[y].add(new Pair(x, z));
        }
        System.out.println(dijk(a));
    }
}

