let dist = Array(n + 1).fill(Infinity);
let ans = Infinity;
for (let i = 0; i < k; i++) {
    dist[a[i]] = 0;
}
let pq = [];
for (let i = 0; i < k; i++) {
    pq.push([0, a[i]]);
}
pq.sort((a, b) => a[0] - b[0]);
while (pq.length) {
    let [d, u] = pq.shift();
    if (d !== dist[u]) continue;
    for (let [v, w] of graph[u]) {
        let nd = d + w;
        if (nd < dist[v]) {
            dist[v] = nd;
            pq.push([nd, v]);
            pq.sort((a, b) => a[0] - b[0]);
        }
    }
